class BingoCard:
    _cards_created = 0   # class variable - shared

    def __init__(self):
        self.grid = []   # instance variable - per object

@classmethod
def how_many_cards(cls):
    return cls._cards_created

BingoCard.how_many_cards()   # no instance needed

